// src/pages/KhaiBaoCoSo.js
import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx (vẫn dùng để đọc CSV)
import './KhaiBaoCoSo.css'; // Import file CSS
import speciesOptions from '../data/speciesData'; // Import danh sách loài từ file mới (nếu có)

function KhaiBaoCoSo() {
  // Initial form state for resetting
  const initialFormState = {
    // Thông tin cơ sở
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
    
    // Người đại diện
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    
    // Cơ sở gây nuôi
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',
    
    // Cơ sở kinh doanh, chế biến gỗ
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',
    
    // Loại cơ sở đăng ký (quan trọng cho việc phân loại)
    loaiCoSoDangKy: '', // Thêm trường này vào initialFormState
    
    // Tên lâm sản và Tên khoa học (áp dụng chung)
    tenLamSan: '', tenKhoaHoc: '',
    
    // Các trường giấy phép
    issueDate: '', expiryDate: '',
    
    // Trạng thái
    trangThai: 'Đang hoạt động', // Mặc định là 'Đang hoạt động'
    ghiChu: '', // Thêm trường ghi chú
  };

  const [formData, setFormData] = useState(initialFormState);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [csvFile, setCsvFile] = useState(null);
  const [excelData, setExcelData] = useState([]); // Dữ liệu từ CSV/Excel
  const [isAdmin, setIsAdmin] = useState(false); // State để kiểm tra quyền admin

  // Kiểm tra quyền admin khi component mount
  useEffect(() => {
    const userRole = localStorage.getItem('role');
    if (userRole === 'admin') {
      setIsAdmin(true);
    } else {
      setIsAdmin(false);
    }
  }, []);

  // Cập nhật tên khoa học khi tên lâm sản thay đổi
  useEffect(() => {
    const selectedSpecies = speciesOptions.find(
      (species) => species.name === formData.tenLamSan
    );
    if (selectedSpecies) {
      setFormData((prev) => ({
        ...prev,
        tenKhoaHoc: selectedSpecies.scientificName,
      }));
    } else {
      setFormData((prev) => ({
        ...prev,
        tenKhoaHoc: '',
      }));
    }
  }, [formData.tenLamSan]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDateChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setMessage('');
    setError('');

    try {
      // Xác định endpoint dựa trên loại cơ sở đăng ký
      const endpoint = 'http://localhost:10000/api/farms'; // Endpoint chung cho cả hai loại hình

      const token = localStorage.getItem('token');
      if (!token) {
        setError('Bạn chưa đăng nhập. Vui lòng đăng nhập để thực hiện chức năng này.');
        setIsLoading(false);
        return;
      }

      const config = {
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      };

      // Chuẩn bị dữ liệu gửi đi, loại bỏ các trường không cần thiết cho backend
      const dataToSend = { ...formData };
      delete dataToSend.loaiHinhCoSo; // Trường này đã bị bỏ trong Farm model và backend route
      delete dataToSend.emailNguoiDaiDien; // Trường này đã bị bỏ trong Farm model và backend route

      const response = await axios.post(endpoint, dataToSend, config);
      setMessage('Đăng ký cơ sở thành công!');
      setFormData(initialFormState); // Reset form
      console.log('Server response:', response.data);
    } catch (err) {
      console.error('Lỗi khi đăng ký cơ sở:', err.response ? err.response.data : err.message);
      setError(err.response?.data?.message || 'Đăng ký cơ sở thất bại. Vui lòng thử lại.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = useCallback((event) => {
    const file = event.target.files[0];
    if (file) {
      setCsvFile(file);
      const reader = new FileReader();
      reader.onload = (e) => {
        const data = new Uint8Array(e.target.result);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        
        // Convert sheet to JSON, ensuring header is read correctly
        // Use raw: false to get formatted values (especially for dates)
        const json = XLSX.utils.sheet_to_json(worksheet, { header: 1, raw: false }); 

        if (json.length > 1) { // Ensure there's at least a header and one row of data
          const headers = json[0]; // First row is headers
          const rows = json.slice(1); // Remaining rows are data

          const parsedData = rows.map(row => {
            const rowData = {};
            headers.forEach((header, index) => {
              // Normalize header names to match backend model fields (lowercase, no spaces, etc.)
              const normalizedHeader = header.trim(); 
              let fieldName = '';

              // Map CSV headers to backend model fields
              switch (normalizedHeader) {
                case 'Tên cơ sở': fieldName = 'tenCoSo'; break;
                case 'Tỉnh (Thành phố)': fieldName = 'tinhThanhPho'; break;
                case 'Xã (Phường)': fieldName = 'xaPhuong'; break;
                case 'Địa chỉ cơ sở': fieldName = 'diaChiCoSo'; break;
                case 'Vĩ độ': fieldName = 'vido'; break;
                case 'Kinh độ': fieldName = 'kinhdo'; break;
                case 'Ngày thành lập': fieldName = 'ngayThanhLap'; break;
                case 'Giấy phép kinh doanh': fieldName = 'giayPhepKinhDoanh'; break;
                case 'Ghi chú': fieldName = 'ghiChu'; break;
                case 'Họ và tên người đại diện': fieldName = 'tenNguoiDaiDien'; break;
                case 'Năm sinh': fieldName = 'namSinh'; break;
                case 'Số CCCD/Hộ chiếu': fieldName = 'soCCCD'; break;
                case 'Ngày cấp CCCD': fieldName = 'ngayCapCCCD'; break;
                case 'Nơi cấp CCCD': fieldName = 'noiCapCCCD'; break;
                case 'Số điện thoại người đại diện': fieldName = 'soDienThoaiNguoiDaiDien'; break;
                case 'Địa chỉ người đại diện': fieldName = 'diaChiNguoiDaiDien'; break;
                case 'Mục đích nuôi': fieldName = 'mucDichNuoi'; break;
                case 'Hình thức nuôi': fieldName = 'hinhThucNuoi'; break;
                case 'Mã số cơ sở gây nuôi': fieldName = 'maSoCoSoGayNuoi'; break;
                case 'Tổng đàn': fieldName = 'tongDan'; break;
                case 'Loại hình kinh doanh gỗ': fieldName = 'loaiHinhKinhDoanhGo'; break;
                case 'Ngành nghề kinh doanh gỗ': fieldName = 'nganhNgheKinhDoanhGo'; break;
                case 'Khối lượng': fieldName = 'khoiLuong'; break;
                case 'Loại cơ sở đăng ký': fieldName = 'loaiCoSoDangKy'; break;
                case 'Tên lâm sản': fieldName = 'tenLamSan'; break;
                case 'Tên khoa học': fieldName = 'tenKhoaHoc'; break;
                case 'Ngày cấp giấy phép': fieldName = 'issueDate'; break;
                case 'Ngày hết hạn giấy phép': fieldName = 'expiryDate'; break;
                case 'Trạng thái': fieldName = 'trangThai'; break;
                default: fieldName = normalizedHeader; // Fallback for unmatched headers
              }

              let value = row[index];

              // Handle specific data type conversions
              if (fieldName.includes('Date') && value) {
                // XLSX.utils.sheet_to_json with raw: false should already format dates as strings.
                // We just need to ensure it's in a format backend expects (ISO string).
                try {
                  const date = new Date(value);
                  if (!isNaN(date.getTime())) {
                    value = date.toISOString(); // Convert to ISO string for backend
                  } else {
                    value = null; // Invalid date
                  }
                } catch (e) {
                  value = null; // Error parsing date
                }
              } else if (fieldName === 'namSinh' || fieldName === 'tongDan') {
                value = parseInt(value, 10); // Convert to integer
                if (isNaN(value)) value = null; // Set to null if not a valid number
              } else if (value === undefined || value === null) {
                value = ''; // Ensure empty strings for missing values to avoid 'undefined'
              }

              rowData[fieldName] = value;
            });
            return rowData;
          });
          setExcelData(parsedData);
          setMessage(`Đã đọc được ${parsedData.length} dòng dữ liệu từ CSV.`);
          setError('');
        } else {
          setExcelData([]);
          setError('File CSV không có dữ liệu hoặc định dạng không đúng.');
          setMessage('');
        }
      };
      reader.readAsArrayBuffer(file); // Read as ArrayBuffer for XLSX
    }
  }, []);

  const handleBulkSubmit = async () => {
    setIsLoading(true);
    setMessage('');
    setError('');

    if (excelData.length === 0) {
      setError('Không có dữ liệu để tải lên hàng loạt.');
      setIsLoading(false);
      return;
    }

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Bạn chưa đăng nhập. Vui lòng đăng nhập để thực hiện chức năng này.');
        setIsLoading(false);
        return;
      }

      const config = {
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      };

      // Gửi dữ liệu hàng loạt đến backend
      const response = await axios.post('http://localhost:10000/api/farms/bulk', excelData, config);
      setMessage(`Tải lên thành công ${response.data.savedFarms.length} cơ sở.`);
      if (response.data.errors && response.data.errors.length > 0) {
        setError(`Có ${response.data.errors.length} lỗi khi tải lên. Vui lòng kiểm tra console để biết chi tiết.`);
        console.error('Bulk upload errors:', response.data.errors);
      }
      setExcelData([]); // Clear data after successful upload
      setCsvFile(null); // Clear file input
    } catch (err) {
      console.error('Lỗi khi tải lên hàng loạt:', err.response ? err.response.data : err.message);
      setError(err.response?.data?.message || 'Tải lên hàng loạt thất bại. Vui lòng kiểm tra lại file và thử lại.');
    } finally {
      setIsLoading(false);
    }
  };

  const resetCsvUpload = () => {
    setCsvFile(null);
    setExcelData([]);
    setMessage('');
    setError('');
  };

  return (
    <div className="khai-bao-container">
      <h2>Đăng ký cơ sở mới</h2>

      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}

      <form onSubmit={handleSubmit} className="khai-bao-form">
        {/* Loại cơ sở đăng ký (dropdown) */}
        <section className="khai-bao-section">
          <h3>Loại hình đăng ký</h3>
          <div className="form-group">
            <label htmlFor="loaiCoSoDangKy">Loại cơ sở đăng ký:</label>
            <select
              id="loaiCoSoDangKy"
              name="loaiCoSoDangKy"
              value={formData.loaiCoSoDangKy}
              onChange={handleChange}
              required
            >
              <option value="">Chọn loại hình</option>
              <option value="Đăng ký cơ sở gây nuôi">Đăng ký cơ sở gây nuôi</option>
              <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Đăng ký cơ sở kinh doanh, chế biến gỗ</option>
            </select>
          </div>
        </section>

        {/* Thông tin cơ sở */}
        <section className="khai-bao-section">
          <h3>Thông tin cơ sở</h3>
          <div className="form-group">
            <label htmlFor="tenCoSo">Tên cơ sở:</label>
            <input
              type="text"
              id="tenCoSo"
              name="tenCoSo"
              value={formData.tenCoSo}
              onChange={handleChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="tinhThanhPho">Tỉnh (Thành phố):</label>
            <input
              type="text"
              id="tinhThanhPho"
              name="tinhThanhPho"
              value={formData.tinhThanhPho}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="xaPhuong">Xã (Phường):</label>
            <input
              type="text"
              id="xaPhuong"
              name="xaPhuong"
              value={formData.xaPhuong}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiCoSo">Địa chỉ cơ sở:</label>
            <input
              type="text"
              id="diaChiCoSo"
              name="diaChiCoSo"
              value={formData.diaChiCoSo}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="vido">Vĩ độ:</label>
            <input
              type="text"
              id="vido"
              name="vido"
              value={formData.vido}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="kinhdo">Kinh độ:</label>
            <input
              type="text"
              id="kinhdo"
              name="kinhdo"
              value={formData.kinhdo}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="ngayThanhLap">Ngày thành lập:</label>
            <input
              type="date"
              id="ngayThanhLap"
              name="ngayThanhLap"
              value={formData.ngayThanhLap}
              onChange={handleDateChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="giayPhepKinhDoanh">Số giấy phép kinh doanh:</label>
            <input
              type="text"
              id="giayPhepKinhDoanh"
              name="giayPhepKinhDoanh"
              value={formData.giayPhepKinhDoanh}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="ghiChu">Ghi chú:</label>
            <textarea
              id="ghiChu"
              name="ghiChu"
              value={formData.ghiChu}
              onChange={handleChange}
              rows="3"
            ></textarea>
          </div>
        </section>

        {/* Thông tin người đại diện */}
        <section className="khai-bao-section">
          <h3>Thông tin người đại diện</h3>
          <div className="form-group">
            <label htmlFor="tenNguoiDaiDien">Họ và tên:</label>
            <input
              type="text"
              id="tenNguoiDaiDien"
              name="tenNguoiDaiDien"
              value={formData.tenNguoiDaiDien}
              onChange={handleChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="namSinh">Năm sinh:</label>
            <input
              type="number"
              id="namSinh"
              name="namSinh"
              value={formData.namSinh}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="soCCCD">Số CCCD/Hộ chiếu:</label>
            <input
              type="text"
              id="soCCCD"
              name="soCCCD"
              value={formData.soCCCD}
              onChange={handleChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="ngayCapCCCD">Ngày cấp CCCD:</label>
            <input
              type="date"
              id="ngayCapCCCD"
              name="ngayCapCCCD"
              value={formData.ngayCapCCCD}
              onChange={handleDateChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="noiCapCCCD">Nơi cấp CCCD:</label>
            <input
              type="text"
              id="noiCapCCCD"
              name="noiCapCCCD"
              value={formData.noiCapCCCD}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="soDienThoaiNguoiDaiDien">Số điện thoại:</label>
            <input
              type="tel"
              id="soDienThoaiNguoiDaiDien"
              name="soDienThoaiNguoiDaiDien"
              value={formData.soDienThoaiNguoiDaiDien}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiNguoiDaiDien">Địa chỉ:</label>
            <input
              type="text"
              id="diaChiNguoiDaiDien"
              name="diaChiNguoiDaiDien"
              value={formData.diaChiNguoiDaiDien}
              onChange={handleChange}
            />
          </div>
        </section>

        {/* Các trường dành riêng cho "Đăng ký cơ sở gây nuôi" */}
        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <section className="khai-bao-section">
            <h3>Thông tin cơ sở gây nuôi</h3>
            <div className="form-group">
              <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
              <input
                type="text"
                id="mucDichNuoi"
                name="mucDichNuoi"
                value={formData.mucDichNuoi}
                onChange={handleChange}
              />
            </div>
            <div className="form-group">
              <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
              <input
                type="text"
                id="hinhThucNuoi"
                name="hinhThucNuoi"
                value={formData.hinhThucNuoi}
                onChange={handleChange}
              />
            </div>
            <div className="form-group">
              <label htmlFor="maSoCoSoGayNuoi">Mã số cơ sở gây nuôi:</label>
              <input
                type="text"
                id="maSoCoSoGayNuoi"
                name="maSoCoSoGayNuoi"
                value={formData.maSoCoSoGayNuoi}
                onChange={handleChange}
              />
            </div>
            <div className="form-group">
              <label htmlFor="tongDan">Tổng đàn:</label>
              <input
                type="number"
                id="tongDan"
                name="tongDan"
                value={formData.tongDan}
                onChange={handleChange}
              />
            </div>
          </section>
        )}

        {/* Các trường dành riêng cho "Đăng ký cơ sở kinh doanh, chế biến gỗ" */}
        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
          <section className="khai-bao-section">
            <h3>Thông tin cơ sở kinh doanh, chế biến gỗ</h3>
            <div className="form-group">
              <label htmlFor="loaiHinhKinhDoanhGo">Loại hình kinh doanh gỗ:</label>
              <input
                type="text"
                id="loaiHinhKinhDoanhGo"
                name="loaiHinhKinhDoanhGo"
                value={formData.loaiHinhKinhDoanhGo}
                onChange={handleChange}
              />
            </div>
            <div className="form-group">
              <label htmlFor="nganhNgheKinhDoanhGo">Ngành nghề kinh doanh gỗ:</label>
              <input
                type="text"
                id="nganhNgheKinhDoanhGo"
                name="nganhNgheKinhDoanhGo"
                value={formData.nganhNgheKinhDoanhGo}
                onChange={handleChange}
              />
            </div>
            <div className="form-group">
              <label htmlFor="khoiLuong">Khối lượng:</label>
              <input
                type="text"
                id="khoiLuong"
                name="khoiLuong"
                value={formData.khoiLuong}
                onChange={handleChange}
              />
            </div>
          </section>
        )}

        {/* Thông tin lâm sản (áp dụng chung) */}
        <section className="khai-bao-section">
          <h3>Thông tin lâm sản</h3>
          <div className="form-group">
            <label htmlFor="tenLamSan">Tên lâm sản:</label>
            <select
              id="tenLamSan"
              name="tenLamSan"
              value={formData.tenLamSan}
              onChange={handleChange}
            >
              <option value="">Chọn lâm sản</option>
              {speciesOptions.map((species, index) => (
                <option key={index} value={species.name}>
                  {species.name}
                </option>
              ))}
            </select>
          </div>
          <div className="form-group">
            <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
            <input
              type="text"
              id="tenKhoaHoc"
              name="tenKhoaHoc"
              value={formData.tenKhoaHoc}
              onChange={handleChange}
              readOnly // Tên khoa học sẽ được tự động điền
            />
          </div>
        </section>

        {/* Thông tin giấy phép */}
        <section className="khai-bao-section">
          <h3>Thông tin Giấy phép</h3>
          <div className="form-group">
            <label htmlFor="issueDate">Ngày cấp:</label>
            <input
              type="date"
              id="issueDate"
              name="issueDate"
              value={formData.issueDate}
              onChange={handleDateChange}
            />
          </div>
          <div className="form-group">
            <label htmlFor="expiryDate">Ngày hết hạn:</label>
            <input
              type="date"
              id="expiryDate"
              name="expiryDate"
              value={formData.expiryDate}
              onChange={handleDateChange}
            />
          </div>
        </section>

        <button type="submit" className="submit-button" disabled={isLoading}>
          {isLoading ? 'Đang lưu...' : 'Lưu thông tin'}
        </button>
      </form>

      {isAdmin && <hr className="section-divider" />}

      {isAdmin && (
        <section className="khai-bao-section excel-upload-section">
          <div className="file-upload-group">
            <label htmlFor="csvUpload" className="file-upload-label">
              Chọn file CSV (.csv):
            </label>
            <input 
              type="file" 
              id="csvUpload" 
              accept=".csv" 
              onChange={handleFileUpload} 
              className="file-input"
            />
            {csvFile && <span className="file-name">{csvFile.name}</span>}
          </div>
          {excelData.length > 0 && (
            <div className="excel-preview-info">
              <p>Đã đọc được {excelData.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.</p>
              <button 
                onClick={handleBulkSubmit} 
                className="submit-button bulk-upload-button"
                disabled={isLoading}
              >
                {isLoading ? 'Đang tải...' : `Tải lên hàng loạt (${excelData.length} cơ sở)`}
              </button>
              <button 
                onClick={resetCsvUpload} 
                className="clear-excel-button"
                disabled={isLoading}
              >
                Xóa dữ liệu CSV
              </button>
            </div>
          )}
        </section>
      )}
    </div>
  );
}

export default KhaiBaoCoSo;
